        this.id = orderId;
    }
}

public class Automobile {
    public static final String OPTION_COLOR_RED = 'red';
    public static final String OPTION_COLOR_WHITE = 'white';
    private String colorValue;
    public String color {
        get { return colorValue; }
        set {
            if (value == OPTION_COLOR_RED || value == OPTION_COLOR_WHITE) {
                colorValue = value;
            } else {
                colorValue = OPTION_COLOR_WHITE;
            }
        }
    }
}

Automobile car = new Automobile();
car.color = 'green';
System.debug(car.color);

public class Person {
    public String firstName { get; set; }
    public String lastName { get; set; }
    public String fullName {
        get { return firstName + ' ' + lastName; }
    }
}

public class Order {
    private String emailValue;
    public String customerEmail {
        get { return emailValue; }
        set {
            emailValue = value;
            if (emailValue != null) emailValue = emailValue.toLowerCase().trim();
        }
    }
    public Decimal subtotal { get; set; }
    public Decimal taxRate { get; set; }
    public Decimal total {
        get { return subtotal + (subtotal * taxRate); }
    }
}
